function normalizeFleetForGateRule(type = "") {
  return String(type || "")
    .trim()
    .toUpperCase()
    .replace(/\s+/g, " ");
}

function isWingboxFleet(type = "") {
  const fleet = normalizeFleetForGateRule(type);
  return fleet.includes("WINGBOX") || fleet.includes("WING BOX");
}

function parseGateList(value = "") {
  return String(value || "")
    .split(/[,;/\n]+/)
    .map((x) => x.trim())
    .filter((x) => x && x !== "-");
}

function uniqueGateList(values = []) {
  return [
    ...new Set(
      (values || []).map((x) => String(x || "").trim()).filter(Boolean),
    ),
  ];
}

function gateSelectOptions(selected = "", allowBlank = false) {
  const selectedList = parseGateList(selected);
  const selectedSet = new Set(selectedList.map((x) => String(x || "").trim()));
  const activeSet =
    typeof getActiveGateSet === "function"
      ? getActiveGateSet(selectedList)
      : new Set();

  const blank = allowBlank
    ? `<option value="" ${!selected ? "selected" : ""}>- Pilih Gate -</option>`
    : "";

  return (
    blank +
    (state.options.gate || [])
      .map((gate) => {
        const gateText = String(gate || "").trim();
        const isSelected =
          selectedSet.has(gateText) || String(gate) === String(selected);
        const isActive = activeSet.has(gateText) && !isSelected;
        return `<option value="${esc(gate)}" ${isSelected ? "selected" : ""} ${isActive ? "disabled" : ""}>${esc(gate)}${isActive ? " — aktif" : ""}</option>`;
      })
      .join("")
  );
}

function checkerGatePicker() {
  return `<label class="flex flex-col gap-2 md:col-span-2">
    <span class="font-label-sm text-label-sm text-on-surface-variant uppercase">Gate</span>
    <input type="hidden" name="gate" id="checker-gate-value" value="" />
    <div id="checker-gate-picker" class="flex flex-col gap-2"></div>
    <div id="checker-gate-help" class="text-[11px] text-on-surface-variant">Pilih gate setelah pilih data checker.</div>
  </label>`;
}

function renderCheckerGatePicker(
  fleetType = "",
  gateValue = "",
  locked = false,
) {
  const wrap = document.getElementById("checker-gate-picker");
  const hidden = document.getElementById("checker-gate-value");
  const help = document.getElementById("checker-gate-help");
  if (!wrap || !hidden) return;

  const gates = parseGateList(gateValue);
  const wingbox = isWingboxFleet(fleetType);
  const disabled = locked ? "disabled" : "";
  const lockedClass = locked ? "opacity-60 cursor-not-allowed" : "";

  if (wingbox) {
    const selected = [gates[0] || "", gates[1] || "", gates[2] || ""];

    wrap.innerHTML = `<div class="grid grid-cols-1 lg:grid-cols-3 gap-2">
      ${[0, 1, 2]
        .map(
          (idx) => `<div class="flex flex-col gap-1">
            <span class="text-[10px] uppercase font-bold text-on-surface-variant">${idx === 0 ? "Gate 1" : `Gate ${idx + 1} Optional`}</span>
            <select data-wingbox-gate="${idx}" class="form-select ${lockedClass}" ${disabled} onchange="syncCheckerGateInput()">
              ${gateSelectOptions(selected[idx], true)}
            </select>
          </div>`,
        )
        .join("")}
    </div>`;

    hidden.value = uniqueGateList(selected).join(", ");
    if (help) {
      help.innerHTML = locked
        ? "Wingbox gate sudah terkunci."
        : "<b>Pilih minimal Gate 1.</b> Wingbox bisa pilih 1 sampai 3 gate berbeda. Gate 2 dan Gate 3 optional.";
    }
  } else {
    const selected = gates[0] || "";
    wrap.innerHTML = `<select data-single-gate="1" class="form-select ${lockedClass}" ${disabled} onchange="syncCheckerGateInput()">
      ${gateSelectOptions(selected, true)}
    </select>`;
    hidden.value = selected;
    if (help)
      help.textContent = locked
        ? "Gate sudah terkunci."
        : "Pilih 1 gate untuk kendaraan ini.";
  }
}

function syncCheckerGateInput() {
  const form = document.getElementById("checker-form");
  const hidden = document.getElementById("checker-gate-value");
  if (!form || !hidden) return true;

  const fleet = form.fleet_type?.value || "";
  if (isWingboxFleet(fleet)) {
    const allSelects = [...document.querySelectorAll("[data-wingbox-gate]")];
    const rawValues = allSelects
      .map((el) => String(el.value || "").trim())
      .filter(Boolean);
    const gates = uniqueGateList(rawValues);

    hidden.value = gates.join(", ");

    const duplicateExists = rawValues.length !== gates.length;
    const ok = gates.length >= 1 && gates.length <= 3 && !duplicateExists;

    allSelects.forEach((el) => {
      const val = String(el.value || "").trim();
      const isDuplicate = val && rawValues.filter((x) => x === val).length > 1;
      const isRequiredEmpty = Number(el.dataset.wingboxGate) === 0 && !val;
      el.classList.toggle("invalid", !ok || isDuplicate || isRequiredEmpty);
    });

    return ok;
  }

  const gate = document.querySelector("[data-single-gate]")?.value || "";
  hidden.value = gate;
  return !!gate;
}

function resetCheckerGatePicker() {
  renderCheckerGatePicker("", "", false);
}

function setCheckerSubmitButtonState(stateName = "ready", label = "") {
  const btn = document.getElementById("checker-submit-btn");
  const txt = document.getElementById("checker-submit-text");
  if (!btn) return;

  const base =
    "mt-6 px-6 py-3 rounded-lg font-bold flex items-center gap-2 transition-all";
  const active =
    "bg-primary-container text-on-primary-container hover:brightness-110";
  const saving =
    "bg-outline-variant text-on-surface-variant cursor-wait opacity-80";
  const done =
    "bg-outline-variant text-on-surface-variant cursor-not-allowed opacity-70";

  if (stateName === "saving") {
    btn.disabled = true;
    btn.className = `${base} ${saving}`;
    if (txt) txt.textContent = label || "Menyimpan...";
    return;
  }

  if (stateName === "done") {
    btn.disabled = true;
    btn.className = `${base} ${done}`;
    if (txt) txt.textContent = label || "Data Sudah Diubah";
    return;
  }

  if (stateName === "completed") {
    btn.disabled = true;
    btn.className = `${base} ${done}`;
    if (txt) txt.textContent = label || "Sudah Selesai";
    return;
  }

  btn.disabled = false;
  btn.className = `${base} ${active}`;
  if (txt && label) txt.textContent = label;
}

function getCheckerActiveRows() {
  return (state.dashboard?.queue || []).filter((r) => {
    const st = String(r.status || "").toUpperCase();
    return !st.includes("COMPLETED") && !st.includes("EXPIRED");
  });
}

function checkerRowKey(row = {}) {
  return poEncode(
    JSON.stringify({
      ticket_id: row.ticket_id || "",
      row_no: row.row_no || "",
      queue_no: row.original_queue_no || row.queue_no || "",
      plat_number: normalizePlateValue(row.plat_number || ""),
      po_number: row.po_number || "",
    }),
  );
}

function findCheckerRowByKey(encodedKey = "") {
  let key = {};
  try {
    key = JSON.parse(poDecode(encodedKey));
  } catch (err) {
    key = {};
  }

  const allRows = state.dashboard?.queue || [];
  const activeRows = getCheckerActiveRows();
  const candidates = activeRows.concat(allRows);

  const ticketId = String(key.ticket_id || "").trim();
  const rowNo = String(key.row_no || "").trim();
  const queueNo = String(key.queue_no || "").trim();
  const plate = normalizePlateValue(key.plat_number || "");
  const po = String(key.po_number || "").trim();

  return (
    candidates.find(
      (row) => ticketId && String(row.ticket_id || "").trim() === ticketId,
    ) ||
    candidates.find(
      (row) => rowNo && String(row.row_no || "").trim() === rowNo,
    ) ||
    candidates.find(
      (row) =>
        queueNo &&
        plate &&
        String(row.original_queue_no || row.queue_no || "").trim() ===
          queueNo &&
        normalizePlateValue(row.plat_number || "") === plate,
    ) ||
    candidates.find(
      (row) =>
        plate &&
        po &&
        normalizePlateValue(row.plat_number || "") === plate &&
        String(row.po_number || "").trim() === po,
    ) ||
    null
  );
}

