    const checkerActive = ["WAITING", "CALLED", "UNLOADING"].includes(st);
    const isCalled = st === "CALLED";
    const isUnloading = st === "UNLOADING";
    const callCount = Number(row.call_count || 0) || 0;
    const cooldown =
      typeof getCallCooldownRemainingSeconds === "function"
